patch:
--- a/comparator.sv
+++ b/comparator.sv
@@ -1,12 +1,12 @@
 module magnitude_comp(
-  output reg a_gt_b,
   input [31:0] val_a,
   input [31:0] val_b,
+  output reg a_gt_b,
   output reg equal
 );
   always @(*) begin
     a_gt_b = (val_a > val_b);
     equal = (val_a == val_b);
   end
 endmodule

 module test_unit(
   input [31:0] sample1, sample2,
-  output gt_flag, eq_flag
+  output gt_flag, eq_flag,
+  output valid
 );
-  magnitude_comp cmp(.a_gt_b(gt_flag), .val_a(sample1), .val_b(sample2), .equal(eq_flag), .valid(valid));
+  magnitude_comp cmp(.val_a(sample1), .val_b(sample2), .a_gt_b(gt_flag), .equal(eq_flag));
 endmodule

before_code:
module magnitude_comp(
  output reg a_gt_b,
  input [31:0] val_a,
  input [31:0] val_b,
  output reg equal
);
  always @(*) begin
    a_gt_b = (val_a > val_b);
    equal = (val_a == val_b);
  end
endmodule

module test_unit(
  input [31:0] sample1, sample2,
  output gt_flag, eq_flag
);
  magnitude_comp cmp(.a_gt_b(gt_flag), .val_a(sample1), .val_b(sample2), .equal(eq_flag), .valid(valid));
endmodule

after_code:
module magnitude_comp(
  input [31:0] val_a,
  input [31:0] val_b,
  output reg a_gt_b,
  output reg equal
);
  always @(*) begin
    a_gt_b = (val_a > val_b);
    equal = (val_a == val_b);
  end
endmodule

module test_unit(
  input [31:0] sample1, sample2,
  output gt_flag, eq_flag
);
  magnitude_comp cmp(.val_a(sample1), .val_b(sample2), .a_gt_b(gt_flag), .equal(eq_flag));
endmodule
